const body = $json.body ?? {};
const onlyDigits = (value) => String(value ?? '').replace(/\D/g, '');
const normalizeBrazilPhone = (value) => {
  const digits = onlyDigits(value);
  if (digits.length === 10 || digits.length === 11) return `55${digits}`;
  return digits;
};
const msg = String(body.text ?? body.message ?? '').replace(/\s+/g, ' ').trim();
const chatId = normalizeBrazilPhone(body.chat_id ?? body.from ?? body.customer_phone_e164 ?? '');
return {
  tenant_id: body.tenant_id || null,
  tenant_phone_e164: normalizeBrazilPhone(body.tenant_phone_e164 ?? body.to ?? body.receiver ?? ''),
  customer_phone_e164: normalizeBrazilPhone(body.customer_phone_e164 ?? body.from ?? body.chat_id ?? ''),
  chat_id: chatId,
  msg,
  raw_body: body
};

const row = Array.isArray($json) ? $json[0] : $json;
const msg = String($node.Normalize.json.msg ?? '').trim();
const customerPhone = String($node.Normalize.json.customer_phone_e164 ?? '').trim();
const payload = row.payload_draft ?? {};
const draft = payload.signup ?? {};
const groups = Array.isArray(row.groups) ? row.groups : [];
const step = row.step || 'billing_signup_welcome';
const tenantName = row.tenant_name || 'nossa equipe';

function reply(text, nextStep, patch = {}, close = false) {
  return [{ json: {
    action: 'patch',
    to: customerPhone || draft.customer_whatsapp,
    reply: text,
    conversation_id: row.conversation_id,
    next_step: nextStep,
    p_close: close,
    data_patch: {
      signup: { ...patch, customer_whatsapp: customerPhone || draft.customer_whatsapp || null },
      metadata: { last_step: nextStep, updated_at: new Date().toISOString() }
    }
  }}];
}

function createSignup() {
  const notes = draft.group_name ? `Grupo/turma informado no WhatsApp: ${draft.group_name}` : 'Cadastro criado via WhatsApp.';
  return [{ json: {
    action: 'create',
    to: customerPhone || draft.customer_whatsapp,
    conversation_id: row.conversation_id,
    next_step: 'billing_signup_done',
    p_close: true,
    create_body: {
      p_tenant_id: row.tenant_id,
      p_full_name: draft.full_name,
      p_whatsapp_e164: customerPhone || draft.customer_whatsapp,
      p_amount_cents: draft.amount_cents,
      p_due_day: draft.due_day,
      p_group_id: draft.group_id || null,
      p_group_name: draft.group_name || null,
      p_notes: notes
    },
    data_patch: {
      signup: { ...draft, customer_whatsapp: customerPhone || draft.customer_whatsapp || null },
      metadata: { completed_at: new Date().toISOString() }
    }
  }}];
}

function normalize(value) {
  return String(value ?? '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();
}

function parseAmountCents(value) {
  const raw = String(value ?? '').trim();
  const numeric = raw.replace(/[^\d,.-]/g, '').replace(/\.(?=\d{3}(\D|$))/g, '').replace(',', '.');
  const amount = Number(numeric);
  if (!Number.isFinite(amount) || amount <= 0) return null;
  return Math.round(amount * 100);
}

function formatMoney(cents) {
  return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(Number(cents || 0) / 100);
}

function renderGroupPrompt() {
  if (!groups.length) return 'Se houver grupo, turma ou categoria, envie o nome. Se nao houver, responda *nenhum*.';
  return 'Escolha o grupo, turma ou categoria:\n' + groups.map((group, index) => `${index + 1}) ${group.name}`).join('\n') + '\n0) Nenhum ou nao sei';
}

function parseGroup(value) {
  const normalized = normalize(value);
  if (['0', 'nenhum', 'nenhuma', 'nao sei', 'não sei', 'sem grupo', 'sem turma'].includes(normalized)) {
    return { group_id: null, group_name: null };
  }
  const selected = groups[Number(value) - 1];
  if (selected) return { group_id: selected.id, group_name: selected.name };
  if (!groups.length && String(value ?? '').trim()) return { group_id: null, group_name: String(value).trim() };
  return null;
}

if (['menu', 'inicio', 'iniciar', '0'].includes(normalize(msg)) || step === 'billing_signup_welcome') {
  const welcome = String(row.welcome_message || '').replaceAll('{{tenant_name}}', tenantName);
  return reply(welcome, 'collect_full_name', {});
}

if (!msg) return reply('Nao recebi nenhuma mensagem. Pode enviar novamente?', step, draft);

if (step === 'collect_full_name') {
  const name = msg.replace(/\s+/g, ' ').trim();
  if (name.split(' ').filter(Boolean).length < 2) return reply('Me informe seu nome completo, por favor. Ex: Maria Silva.', step, draft);
  return reply(renderGroupPrompt(), 'collect_group', { ...draft, full_name: name });
}

if (step === 'collect_group') {
  const group = parseGroup(msg);
  if (!group) return reply(renderGroupPrompt(), step, draft);
  return reply('Qual e o valor da mensalidade? Ex: 120,00', 'collect_amount', { ...draft, ...group });
}

if (step === 'collect_amount') {
  const amountCents = parseAmountCents(msg);
  if (!amountCents) return reply('Nao consegui entender o valor. Envie assim: 120,00', step, draft);
  return reply('Qual e o dia de vencimento da mensalidade? Envie um numero de 1 a 31.', 'collect_due_day', { ...draft, amount_cents: amountCents });
}

if (step === 'collect_due_day') {
  const dueDay = Number(String(msg).replace(/\D/g, ''));
  if (!Number.isInteger(dueDay) || dueDay < 1 || dueDay > 31) return reply('Envie um dia de vencimento valido, de 1 a 31.', step, draft);
  const merged = { ...draft, due_day: dueDay };
  const summary = 'Confira o cadastro:\n\nNome: ' + merged.full_name + '\nWhatsApp: ' + (customerPhone || merged.customer_whatsapp) + '\nGrupo/turma: ' + (merged.group_name || 'Nenhum') + '\nMensalidade: ' + formatMoney(merged.amount_cents) + '\nVencimento: dia ' + dueDay + '\n\nResponda *sim* para confirmar ou *0* para recomecar.';
  return reply(summary, 'confirm_signup', merged);
}

if (step === 'confirm_signup') {
  if (!['sim', 's', 'confirmar', 'confirmo'].includes(normalize(msg))) return reply('Tudo bem. Responda *sim* para confirmar ou envie *0* para recomecar.', step, draft);
  return createSignup();
}

return reply('Vamos recomecar. Me informe seu nome completo.', 'collect_full_name', {});

const original = $node.FN_signup_state_machine.json;
const data = Array.isArray($json) ? $json[0] : $json;
return [{ json: {
  to: original.to,
  reply: 'Recebi seus dados! 😊 Enviei o cadastro para o professor conferir. Assim que ele aprovar, seu aluno e a mensalidade aparecerão no painel.',
  conversation_id: original.conversation_id,
  next_step: 'billing_signup_pending_approval',
  p_close: true,
  data_patch: {
    ...original.data_patch,
    signup: {
      ...original.data_patch.signup,
      request_id: data.request_id,
      request_status: data.request_status
    },
    metadata: { submitted_at: new Date().toISOString() }
  }
}}];
